import json
import base64
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
import functions_framework
from datetime import datetime

# Initialize clients
storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

PROJECT_ID = 'your-project-id'
PUBSUB_TOPIC = f'projects/{PROJECT_ID}/topics/file-processing-topic'

@functions_framework.cloud_event
def process_storage_file(cloud_event):
    """
    Triggered by Cloud Storage when a file is uploaded.
    Processes the file, writes metadata to Firestore, and publishes to Pub/Sub.
    """
    data = cloud_event.data
    
    bucket_name = data['bucket']
    file_name = data['name']
    
    # Read file from Cloud Storage
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    
    file_content = blob.download_as_text()
    file_metadata = {
        'name': file_name,
        'bucket': bucket_name,
        'size': blob.size,
        'content_type': blob.content_type,
        'created': blob.time_created.isoformat() if blob.time_created else None,
        'updated': blob.updated.isoformat() if blob.updated else None,
        'processed_at': datetime.utcnow().isoformat()
    }
    
    # Process file content (example: count lines)
    lines = file_content.split('\n')
    file_metadata['line_count'] = len(lines)
    file_metadata['preview'] = lines[0][:100] if lines else ''
    
    # Write to Firestore
    doc_ref = firestore_client.collection('processed_files').document()
    doc_ref.set(file_metadata)
    
    # Publish to Pub/Sub
    message_data = {
        'file_name': file_name,
        'bucket': bucket_name,
        'firestore_doc_id': doc_ref.id,
        'status': 'processed',
        'timestamp': datetime.utcnow().isoformat()
    }
    
    message_json = json.dumps(message_data)
    message_bytes = message_json.encode('utf-8')
    
    future = publisher.publish(PUBSUB_TOPIC, message_bytes)
    message_id = future.result()
    
    print(f'Processed file: {file_name}')
    print(f'Firestore document ID: {doc_ref.id}')
    print(f'Pub/Sub message ID: {message_id}')
    
    return {'status': 'success', 'message_id': message_id, 'doc_id': doc_ref.id}


@functions_framework.http
def process_http_request(request):
    """
    HTTP triggered function that can manually process files.
    Accepts JSON with bucket and file_name parameters.
    """
    request_json = request.get_json(silent=True)
    
    if not request_json or 'bucket' not in request_json or 'file_name' not in request_json:
        return {'error': 'Missing bucket or file_name parameter'}, 400
    
    bucket_name = request_json['bucket']
    file_name = request_json['file_name']
    
    try:
        # Read file from Cloud Storage
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        if not blob.exists():
            return {'error': f'File {file_name} not found in bucket {bucket_name}'}, 404
        
        file_content = blob.download_as_text()
        file_metadata = {
            'name': file_name,
            'bucket': bucket_name,
            'size': blob.size,
            'content_type': blob.content_type,
            'created': blob.time_created.isoformat() if blob.time_created else None,
            'updated': blob.updated.isoformat() if blob.updated else None,
            'processed_at': datetime.utcnow().isoformat()
        }
        
        # Process file content
        lines = file_content.split('\n')
        file_metadata['line_count'] = len(lines)
        file_metadata['preview'] = lines[0][:100] if lines else ''
        
        # Write to Firestore
        doc_ref = firestore_client.collection('processed_files').document()
        doc_ref.set(file_metadata)
        
        # Publish to Pub/Sub
        message_data = {
            'file_name': file_name,
            'bucket': bucket_name,
            'firestore_doc_id': doc_ref.id,
            'status': 'processed',
            'timestamp': datetime.utcnow().isoformat()
        }
        
        message_json = json.dumps(message_data)
        message_bytes = message_json.encode('utf-8')
        
        future = publisher.publish(PUBSUB_TOPIC, message_bytes)
        message_id = future.result()
        
        return {
            'status': 'success',
            'file_name': file_name,
            'firestore_doc_id': doc_ref.id,
            'pubsub_message_id': message_id,
            'line_count': file_metadata['line_count']
        }, 200
        
    except Exception as e:
        return {'error': str(e)}, 500


@functions_framework.cloud_event
def process_pubsub_message(cloud_event):
    """
    Triggered by Pub/Sub messages.
    Processes messages and updates Firestore.
    """
    pubsub_message = base64.b64decode(cloud_event.data['message']['data']).decode('utf-8')
    message_data = json.loads(pubsub_message)
    
    print(f'Received Pub/Sub message: {message_data}')
    
    # Update Firestore with additional processing
    if 'firestore_doc_id' in message_data:
        doc_ref = firestore_client.collection('processed_files').document(message_data['firestore_doc_id'])
        doc_ref.update({
            'pubsub_processed': True,
            'pubsub_processed_at': datetime.utcnow().isoformat()
        })
    
    # Create audit log in Firestore
    audit_ref = firestore_client.collection('audit_logs').document()
    audit_ref.set({
        'event_type': 'pubsub_message_processed',
        'message_data': message_data,
        'timestamp': datetime.utcnow().isoformat()
    })
    
    return {'status': 'processed'}


def list_processed_files(limit=10):
    """
    Helper function to list processed files from Firestore.
    """
    docs = firestore_client.collection('processed_files').limit(limit).stream()
    
    files = []
    for doc in docs:
        file_data = doc.to_dict()
        file_data['id'] = doc.id
        files.append(file_data)
    
    return files


def get_file_stats(bucket_name):
    """
    Helper function to get statistics about files in a bucket.
    """
    bucket = storage_client.bucket(bucket_name)
    blobs = bucket.list_blobs()
    
    total_size = 0
    file_count = 0
    
    for blob in blobs:
        total_size += blob.size
        file_count += 1
    
    stats = {
        'bucket': bucket_name,
        'file_count': file_count,
        'total_size_bytes': total_size,
        'total_size_mb': round(total_size / (1024 * 1024), 2)
    }
    
    # Store stats in Firestore
    stats_ref = firestore_client.collection('bucket_stats').document(bucket_name)
    stats_ref.set({
        **stats,
        'updated_at': datetime.utcnow().isoformat()
    })
    
    return stats